---
import BaseLayout from '../../layouts/BaseLayout.astro';
import { Image } from 'astro:assets';
import { getCollection, render } from 'astro:content';
import { formatDate } from '../../utils/format-date';

export async function getStaticPaths() {
  const isDev = import.meta.env.DEV;
  const posts = await getCollection('blog', ({ data }) => isDev || !data.draft);
  return posts.map((post) => ({
    params: { id: post.id },
    props: { post },
  }));
}

const { post } = Astro.props;
const { Content, remarkPluginFrontmatter } = await render(post);
const minutesRead: string = remarkPluginFrontmatter.minutesRead ?? '1 min read';
const wordCount: number = remarkPluginFrontmatter.wordCount ?? 0;

const siteBase = Astro.site ?? new URL(Astro.url.origin);
const postUrl = new URL(Astro.url.pathname, siteBase).href;
const ogImageUrl = new URL(`/blog/${post.id}/og.png`, siteBase).href;

const blogPostingSchema = {
  "@context": "https://schema.org",
  "@type": "BlogPosting",
  "headline": post.data.title,
  "description": post.data.description,
  "datePublished": post.data.date.toISOString(),
  "dateModified": (post.data.updatedDate ?? post.data.date).toISOString(),
  "author": {
    "@type": "Person",
    "name": post.data.author ?? 'Site Author',
    ...(post.data.authorUrl ? { "url": post.data.authorUrl } : {}),
  },
  "publisher": {
    "@type": "Organization",
    "name": "AstroStatic",
    "url": new URL('/', siteBase).href,
  },
  "url": postUrl,
  "mainEntityOfPage": {
    "@type": "WebPage",
    "@id": postUrl,
  },
  "image": ogImageUrl,
  "inLanguage": "en-US",
  "keywords": post.data.tags.join(', '),
  "wordCount": wordCount,
};

const breadcrumbSchema = {
  "@context": "https://schema.org",
  "@type": "BreadcrumbList",
  "itemListElement": [
    { "@type": "ListItem", "position": 1, "name": "Home", "item": new URL('/', siteBase).href },
    { "@type": "ListItem", "position": 2, "name": "Blog", "item": new URL('/blog', siteBase).href },
    { "@type": "ListItem", "position": 3, "name": post.data.title, "item": postUrl },
  ],
};
---

<BaseLayout
  title={`${post.data.title} - AstroStatic`}
  description={post.data.description}
  image={ogImageUrl}
  imageAlt={post.data.imageAlt}
  type="article"
  articleMeta={{
    publishedTime: post.data.date.toISOString(),
    modifiedTime: post.data.updatedDate?.toISOString(),
    author: post.data.author,
    tags: post.data.tags,
  }}
>
  <Fragment slot="head">
    <script type="application/ld+json" set:html={JSON.stringify(blogPostingSchema)} />
    <script type="application/ld+json" set:html={JSON.stringify(breadcrumbSchema)} />
  </Fragment>
  <article class="mx-auto max-w-3xl px-4 py-16">
    <header class="mb-8">
      <a href="/blog" class="text-sm text-blue-600 dark:text-blue-400 hover:underline rounded focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600 dark:focus-visible:outline-blue-400">&larr; Back to blog</a>
      <h1 class="mt-4 text-4xl font-bold">{post.data.title}</h1>
      <div class="mt-2 flex items-center gap-3 text-sm text-gray-500 dark:text-gray-400">
        <time datetime={post.data.date.toISOString().split('T')[0]}>
          {formatDate(post.data.date)}
        </time>
        <span aria-hidden="true">&middot;</span>
        <span>{minutesRead}</span>
      </div>
      {post.data.tags.length > 0 && (
        <div class="mt-3 flex flex-wrap gap-2">
          {post.data.tags.map((tag) => (
            <a
              href={`/blog/tags/${encodeURIComponent(tag)}`}
              class="inline-flex items-center rounded-full bg-gray-100 dark:bg-gray-800 px-2.5 py-0.5 text-xs font-medium text-gray-600 dark:text-gray-400 hover:bg-blue-100 dark:hover:bg-blue-900 hover:text-blue-700 dark:hover:text-blue-300 transition-colors focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-500"
            >
              {tag}
            </a>
          ))}
        </div>
      )}
    </header>
    {post.data.image && (
      <Image
        src={post.data.image}
        alt={post.data.imageAlt ?? ''}
        priority
        class="w-full rounded-xl mb-8 object-cover"
      />
    )}
    <div class="prose prose-gray dark:prose-invert max-w-none">
      <Content />
    </div>
  </article>
</BaseLayout>

---
interface Props {
  title: string;
  description: string;
  canonicalURL?: URL | string;
  image?: string;
  imageAlt?: string;
  type?: 'website' | 'article';
}

const {
  title,
  description,
  canonicalURL = Astro.url,
  image = '/og-default.png',
  imageAlt = description,
  type = 'website',
} = Astro.props;

const siteUrl = import.meta.env.SITE_URL || Astro.site?.toString() || '';
const absoluteImage = image.startsWith('http') ? image : `${siteUrl}${image}`;
---

<!-- Canonical -->
<link rel="canonical" href={canonicalURL.toString()} />

<!-- Open Graph -->
<meta property="og:type" content={type === 'article' ? 'article' : 'website'} />
<meta property="og:url" content={canonicalURL.toString()} />
<meta property="og:title" content={title} />
<meta property="og:description" content={description} />
<meta property="og:image" content={absoluteImage} />
<meta property="og:locale" content="en_US" />

<!-- Twitter Card -->
<meta name="twitter:card" content="summary_large_image" />
<meta name="twitter:title" content={title} />
<meta name="twitter:description" content={description} />
<meta name="twitter:image" content={absoluteImage} />
<meta name="twitter:image:alt" content={imageAlt} />

